GameServerApp::GameServerApp()
    : m_count(0)
{
	ToLogService("common", "start init ServerApp");

	srand( (unsigned)time( NULL ) );

    m_strGameName = g_Config.m_szName;

    // Инициализация GateServer массива
    m_gtnum = min(MAX_GATE, g_Config.m_nGateCnt);
    for (int i = 0; i < m_gtnum; ++i)
    {
        m_gtarray[i].GetIP() = g_Config.m_szGateIP[i];
        m_gtarray[i].GetPort() = g_Config.m_nGatePort[i];
        m_gtarray[i].m_playerlist = NULL;
        m_gateHandlers[i].Init(i, this);
        m_gateClients[i].SetHandler(&m_gateHandlers[i]);
    }

    // Инициализация InfoServer
    m_IfServer.SetInfoServer(g_Config.m_szInfoIP, g_Config.m_nInfoPort, g_Config.m_szInfoPwd, g_Config.m_nSection);

    // Запуск фонового потока переподключения
    m_connectThread = std::thread(&GameServerApp::ConnectGateLoop, this);

	ToLogService("common", "ServerApp init over");
}

GameServerApp::~GameServerApp()
{
	if(m_IfServer.IsConnect())
	{
		DisconnectInfo(&m_IfServer);
		ToLogService("store", "Disconnect InfoServer!");
	}

    // Остановка потока переподключения
    m_exitFlag.store(true);
    if (m_connectThread.joinable())
        m_connectThread.join();

    // Отключение всех GateServer'ов
    for (int i = 0; i < m_gtnum; ++i)
    {
        m_gateClients[i].Disconnect();
        m_gtarray[i].Invalid();
    }
}

// ════════════════════════════════════════════════════════════
//  ConnectGateLoop — фоновый поток переподключения (замена ConnectGateServer::Process)
// ════════════════════════════════════════════════════════════

void GameServerApp::ConnectGateLoop()
{
    DWORD dwInterval = 5000;

    while (!m_exitFlag.load())
    {
        for (int i = 0; i < 1; i++)
        {
            if (m_exitFlag.load()) return;

            if (!m_gtarray[i].IsValid() && !m_gateClients[i].IsConnected())
            {
                ToLogService("network", "connecting to GateServer {}:{}...",
                    m_gtarray[i].GetIP().c_str(), m_gtarray[i].GetPort());

                if (m_gateClients[i].Connect(m_gtarray[i].GetIP().c_str(), m_gtarray[i].GetPort()))
                {
                    m_gtarray[i].SetClient(&m_gateClients[i]);
                    // Уведомляем game thread о новом подключении
                    m_pendingConnect.store(i);
                    ToLogService("network", "GateServer connected: {}:{}",
                        m_gtarray[i].GetIP().c_str(), m_gtarray[i].GetPort());
                }
                else
                {
                    ToLogService("network", "connect to GateServer failed, ip = {}, port = {}.",
                        m_gtarray[i].GetIP().c_str(), m_gtarray[i].GetPort());
                }
            }
        }
        Sleep(dwInterval);
    }
}

// ════════════════════════════════════════════════════════════
//  HandlePendingEvents — обработка connect/disconnect из game thread
// ════════════════════════════════════════════════════════════

void GameServerApp::HandlePendingEvents()
{
    // Обработка pending connect
    int ci = m_pendingConnect.exchange(-1);
    if (ci >= 0 && ci < m_gtnum)
    {
        GateServer* gt = &m_gtarray[ci];
        // Типизированная сериализация: синтетический пакет подключения GateServer
        auto wpkt = net::msg::serializeGmGateConnectCmd();
        net::RPacket rpkt(wpkt.Data(), wpkt.GetPacketSize(), false);
        g_pGameApp->ProcessNetMsg(NETMSG_GATE_CONNECTED, gt, rpkt);
    }

    // Обработка pending disconnect
    int di = m_pendingDisconnect.exchange(-1);
    if (di >= 0 && di < m_gtnum)
    {
        auto const lock = std::lock_guard{m_mutdisconn};
        GateServer* gt = &m_gtarray[di];
        if (gt->IsValid() || gt->m_playerlist != nullptr)
        {
            // Типизированная сериализация: синтетический пакет отключения GateServer с указателем playerlist
            auto wpkt = net::msg::serializeGmGateDisconnect(ToAddress(gt->m_playerlist));
            net::RPacket rpkt(wpkt.Data(), wpkt.GetPacketSize(), false);
            g_pGameApp->ProcessNetMsg(NETMSG_GATE_DISCONNECT, gt, rpkt);
        }
    }
}

// ════════════════════════════════════════════════════════════
//  PeekPacket — опрос всех gate-подключений (замена PKQueue::PeekPacket)
// ════════════════════════════════════════════════════════════

void GameServerApp::PeekPacket(unsigned long ms)
{
    DWORD start = GetTickCount();

    do
    {
        HandlePendingEvents();

        int processed = 0;
        for (int i = 0; i < m_gtnum; i++)
        {
            if (m_gateClients[i].IsConnected())
                processed += m_gateClients[i].PollPackets(50);
        }

        DWORD elapsed = GetTickCount() - start;
        if (elapsed >= ms) break;

        if (processed == 0) Sleep(1);

    } while (true);
}

// ════════════════════════════════════════════════════════════
