bool GameServerApp::SendToGroup(net::WPacket& chginf)
{
    GateServer* pGate;

    for (int i = 0; i < m_gtnum; ++ i)
    {
        pGate = &m_gtarray[i];

        if (pGate->IsValid())
        {
			chginf.WriteInt64( 0 );
			pGate->SendData(chginf);
			return true;
        }
	}
    return true;
}

bool GameServerApp::SendToWorld(net::WPacket& chginf)
{
    net::WPacket CChginf;
    short        sCount;

    GatePlayer* pPlayer;
    GateServer* pGate;

    for (int i = 0; i < m_gtnum; ++ i)
    {
        pGate = &m_gtarray[i];

        if (pGate->IsValid())
        {
            sCount = 0;
            CChginf = chginf.Duplicate();

			pPlayer = pGate->m_playerlist;
            while (pPlayer != NULL)
            {
                CChginf.WriteInt64(pPlayer->GetDBChaId());
                CChginf.WriteInt64(pPlayer->GetGateAddr());
                sCount++;

                pPlayer = pPlayer->Next;
            }

            if (sCount > 0)
            {
                CChginf.WriteInt64(sCount);
                pGate->SendData(CChginf);
            }
        }
    }

    return true;
}

bool GameServerApp::SendToClient(GatePlayer* player, net::WPacket& pkt)
{
    if (player == NULL) return false;

    GateServer* pGate = player->GetGate();
    if (pGate != NULL)
    {
        pGate->SendData(pkt);
        return true;
    }
    else
    {
        return false;
    }
}

bool GameServerApp::SendToClient(net::WPacket& pkt, GatePlayer* playerlist)
{
    if (playerlist == NULL) return false;

    unsigned short usCount[MAX_GATE];
    net::WPacket   CChginf[MAX_GATE];
    GateServer*    pValidGate[MAX_GATE];
    short          sValidGateNum = 0;
    for (int i = 0; i < m_gtnum; ++ i)
    {
        if (m_gtarray[i].IsValid())
        {
            pValidGate[sValidGateNum] = &m_gtarray[i];
            usCount[sValidGateNum] = 0;
            CChginf[sValidGateNum] = pkt.Duplicate();
            sValidGateNum++;
        }
    }

    GatePlayer* tmp = playerlist;
    while (tmp != NULL)
    {
        if (tmp->GetGate() == NULL)
        {
#ifdef defCOMMU_LOG
            ToLogService("common", "WARNING! pGate = NULL, atorID={}, gt_addr=0x{:x}",
                tmp->GetDBChaId(), tmp->GetGateAddr());
#endif
        }
        else
        {
            for (int i = 0; i < sValidGateNum; ++ i)
            {
                if (tmp->GetGate() == pValidGate[i])
                {
                    usCount[i]++;
                    CChginf[i].WriteInt64(tmp->GetDBChaId());
                    CChginf[i].WriteInt64(tmp->GetGateAddr());
                    break;
                }
            }
        }

        tmp = tmp->GetNextPlayer();
    }

    for (int i = 0; i < sValidGateNum; i++)
    {
        if (usCount[i] > 0)
        {
            CChginf[i].WriteInt64(usCount[i]);
            pValidGate[i]->SendData(CChginf[i]);
        }
    }

    return true;
}

bool GameServerApp::SendToClient(net::WPacket& pkt, int array_cnt, uplayer* uplayer_array)
{
    if (uplayer_array == NULL) return false;

    unsigned short usCount[MAX_GATE];
    net::WPacket   CChginf[MAX_GATE];
    GateServer*    pValidGate[MAX_GATE];
    short          sValidGateNum = 0;
    for (int i = 0; i < m_gtnum; ++ i)
    {
        if (m_gtarray[i].IsValid())
        {
            pValidGate[sValidGateNum] = &m_gtarray[i];
            usCount[sValidGateNum] = 0;
            CChginf[sValidGateNum] = pkt.Duplicate();
            sValidGateNum++;
        }
    }

    int j;
    for (int i = 0; i < array_cnt; ++ i)
    {
        if (uplayer_array[i].pGate == NULL)
        {
#ifdef defCOMMU_LOG
            ToLogService("common", "WARNING! pGate = NULL, atorID={}, gt_addr=0x{:x}",
                uplayer_array[i].m_dwDBChaId, uplayer_array[i].m_ulGateAddr);
#endif
            continue;
        }

        for (j = 0; j < sValidGateNum; ++ j)
        {
            if (uplayer_array[i].pGate == pValidGate[j])
            {
                usCount[j]++;
                CChginf[j].WriteInt64(uplayer_array[i].m_dwDBChaId);
                CChginf[j].WriteInt64(uplayer_array[i].m_ulGateAddr);
                break;
            }
        }
    }

    for (int i = 0; i < sValidGateNum; i++)
    {
        if (usCount[i] > 0)
        {
            CChginf[i].WriteInt64(usCount[i]);
            pValidGate[i]->SendData(CChginf[i]);
        }
    }

    return true;
}

bool GameServerApp::SendToGame(net::WPacket& pkt, uplayer* uplyr)
{
    return uplyr->pGate->SendData(pkt);
}


